import "./App.css";
import Navbar from "./components/navbar";
import Slider from "./components/carousal";
import Cards from "./components/cards";
import { BrowserRouter as Router, Route, Switch } from "react-router-dom";

function App() {
  return (
    <Router>
      <div className="App">
        <Navbar />
        <Slider />
        <Cards />
      </div>
    </Router>
  );
}

export default App;
